import { Link } from "react-router-dom";
import { useSepet } from "../context/SepetContext";

export default function UrunCard({ urun }) {
  return (
    <div className="border rounded-lg p-4 shadow hover:shadow-lg transition-all">
      {urun.gorsel && (
        <img
          src={urun.gorsel}
          alt={urun.ad}
          className="w-full h-40 object-contain mb-2"
        />
      )}
      <h3 className="text-lg font-bold">{urun.ad}</h3>
      <p className="text-sm text-gray-600 mb-1">{urun.aciklama}</p>
      <p className="text-sm text-gray-500 italic mb-1">{urun.kategori}</p>
      <p className="text-lg font-semibold text-green-700">{urun.fiyat} ₺</p>
    </div>
  );
}
